#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <omp.h>

#define INF 1000000000

int main(int argc, char **argv) {
  if (argc != 3) {
    printf("Usage: %s <n> <num_threads>\n", argv[0]);
    return 1;
  }

  int n = atoi(argv[1]);
  int num_threads = atoi(argv[2]);

  int *dist = (int*)malloc(n * n * sizeof(int));
  if (!dist) {
    printf("Failed to allocate memory\n");
    return 1;
  }

  // Initialize the distance matrix
  for (int i = 0; i < n; i++) {
    for (int j = 0; j < n; j++) {
      if (i == j)
        dist[i * n + j] = 0;
      else
        dist[i * n + j] = INF;
    }
  }

  // Read edges from stdin
  int u, v, w;
  while (scanf("%d %d %d", &u, &v, &w) == 3) {
    if (u >= 0 && u < n && v >= 0 && v < n) {
      dist[u * n + v] = w;
    }
  }

  omp_set_num_threads(num_threads);

  // Floyd-Warshall algorithm
  for (int k = 0; k < n; k++) {
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < n; i++) {
      int *dist_i = &dist[i * n];
      int dist_ik = dist_i[k];
      for (int j = 0; j < n; j++) {
        int new_dist = dist_ik + dist[k * n + j];
        if (new_dist < dist_i[j]) {
          dist_i[j] = new_dist;
        }
      }
    }
  }

  // Print the distance matrix
  for (int i = 0; i < n; i++) {
    for (int j = 0; j < n; j++) {
      if (dist[i * n + j] == INF)
        printf("INF ");
      else
        printf("%d ", dist[i * n + j]);
    }
    printf("\n");
  }

  free(dist);

  return 0;
}
